// Fail-fast contract validation against §295 (§298).
// Delegates to the runnable engine wf004_output_generation._validate_result.
// In deployment this Code node calls the shared validator; here it asserts
// required fields exist before assembly.
for (const item of items) {
  const r = item.json;
  if (r.schemaVersion !== '1.1') { throw new Error('schemaVersion must be 1.1 (§296)'); }
  for (const f of ['requirementId','requirement','complianceLevel']) {
    if (r[f] === undefined || r[f] === null) { throw new Error('missing ' + f + ' (§295)'); }
  }
}
return items;

// Assemble Proposal Package (§552) + audit trail (§112).
// Deterministic export (§113). Emits the proposal_package.contract.json shape.
return items;
